"use client";

import { useState, useEffect } from "react";
import { CopyPlus, Plus, Loader2 } from "lucide-react";

export default function AdminCategories() {
    const [categories, setCategories] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    const [isAdding, setIsAdding] = useState(false);
    const [editingId, setEditingId] = useState<string | null>(null);
    const [formData, setFormData] = useState({
        name: "",
        slug: "",
        type: "product",
        image: "",
    });

    const fetchCategories = async () => {
        setLoading(true);
        const res = await fetch("/api/categories");
        const data = await res.json();
        if (data.success) setCategories(data.data);
        setLoading(false);
    };

    useEffect(() => {
        fetchCategories();
    }, []);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        const url = editingId ? `/api/categories/${editingId}` : "/api/categories";
        const method = editingId ? "PUT" : "POST";

        const res = await fetch(url, {
            method,
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(formData),
        });
        if (res.ok) {
            setFormData({ name: "", slug: "", type: "product", image: "" });
            setIsAdding(false);
            setEditingId(null);
            fetchCategories();
        }
    };

    const handleEdit = (category: any) => {
        setFormData({
            name: category.name,
            slug: category.slug,
            type: category.type,
            image: category.image || "",
        });
        setEditingId(category._id);
        setIsAdding(true);
    };

    const handleDelete = async (id: string) => {
        if (!confirm("Are you sure you want to delete this category?")) return;
        const res = await fetch(`/api/categories/${id}`, { method: "DELETE" });
        if (res.ok) fetchCategories();
    };

    return (
        <div className="space-y-8 animate-in fade-in">
            <div className="flex justify-between items-center bg-white dark:bg-gray-900 p-6 rounded-[2rem] border dark:border-gray-800 shadow-sm">
                <h1 className="text-3xl font-black text-gray-900 dark:text-white flex items-center gap-3">
                    <CopyPlus className="text-blue-600 dark:text-blue-400" /> Categories
                </h1>
                <button
                    onClick={() => {
                        setIsAdding(!isAdding);
                        if (isAdding) setEditingId(null);
                    }}
                    className="flex items-center gap-2 bg-blue-600 text-white px-5 py-3 rounded-xl font-bold hover:bg-blue-700 transition-colors shadow-lg shadow-blue-600/30 dark:shadow-blue-900/40"
                >
                    {isAdding ? "Cancel" : <><Plus className="w-5 h-5" /> Add Category</>}
                </button>
            </div>

            {isAdding && (
                <form
                    onSubmit={handleSubmit}
                    className="bg-white dark:bg-gray-900 p-8 rounded-[2rem] border dark:border-gray-800 shadow-sm space-y-6 animate-in slide-in-from-top-4"
                >
                    <h2 className="text-xl font-bold border-b dark:border-gray-800 pb-4 dark:text-white">{editingId ? "Edit Category" : "Add New Category"}</h2>
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div>
                            <label className="block text-sm font-bold mb-2 text-gray-700 dark:text-gray-300">Name</label>
                            <input
                                type="text"
                                required
                                value={formData.name}
                                onChange={(e) =>
                                    setFormData({
                                        ...formData,
                                        name: e.target.value,
                                        slug: e.target.value.toLowerCase().replace(/\s+/g, "-"),
                                    })
                                }
                                className="w-full bg-white dark:bg-gray-800 border dark:border-gray-700 p-4 rounded-xl text-gray-900 dark:text-white focus:ring-4 focus:ring-blue-100 dark:focus:ring-blue-900/50 focus:border-blue-500 outline-none transition-all font-medium"
                                placeholder="e.g. Groceries"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-bold mb-2 text-gray-700 dark:text-gray-300">Slug</label>
                            <input
                                type="text"
                                required
                                value={formData.slug}
                                onChange={(e) => setFormData({ ...formData, slug: e.target.value })}
                                className="w-full bg-white dark:bg-gray-800 border dark:border-gray-700 p-4 rounded-xl text-gray-900 dark:text-white focus:ring-4 focus:ring-blue-100 dark:focus:ring-blue-900/50 focus:border-blue-500 outline-none transition-all font-medium"
                                placeholder="e.g. groceries"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-bold mb-2 text-gray-700 dark:text-gray-300">Type</label>
                            <select
                                value={formData.type}
                                onChange={(e) => setFormData({ ...formData, type: e.target.value })}
                                className="w-full bg-white dark:bg-gray-800 border dark:border-gray-700 p-4 rounded-xl text-gray-900 dark:text-white focus:ring-4 focus:ring-blue-100 dark:focus:ring-blue-900/50 focus:border-blue-500 outline-none transition-all font-medium"
                                required
                            >
                                <option value="product">Product based (Uses Cart)</option>
                                <option value="service">Service based (Uses Forms)</option>
                            </select>
                        </div>
                        <div>
                            <label className="block text-sm font-bold mb-2 text-gray-700 dark:text-gray-300">Image URL</label>
                            <input
                                type="url"
                                value={formData.image}
                                onChange={(e) => setFormData({ ...formData, image: e.target.value })}
                                className="w-full bg-white dark:bg-gray-800 border dark:border-gray-700 p-4 rounded-xl text-gray-900 dark:text-white focus:ring-4 focus:ring-blue-100 dark:focus:ring-blue-900/50 focus:border-blue-500 outline-none transition-all font-medium"
                                placeholder="https://images.unsplash.com/..."
                            />
                        </div>
                    </div>
                    <button
                        type="submit"
                        className="bg-gray-900 dark:bg-gray-100 text-white dark:text-gray-900 px-8 py-4 rounded-xl font-black text-lg hover:bg-black dark:hover:bg-white transition-colors w-full md:w-auto"
                    >
                        Save Category
                    </button>
                </form>
            )}

            {loading ? (
                <div className="py-20 flex justify-center">
                    <Loader2 className="w-10 h-10 animate-spin text-blue-600 dark:text-blue-400" />
                </div>
            ) : (
                <div className="bg-white dark:bg-gray-900 rounded-[2rem] border dark:border-gray-800 shadow-sm overflow-hidden">
                    <div className="overflow-x-auto">
                        <table className="w-full text-left border-collapse">
                            <thead className="bg-gray-50 dark:bg-gray-800 border-b dark:border-gray-700">
                                <tr>
                                    <th className="p-5 font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider text-sm w-16">
                                        Image
                                    </th>
                                    <th className="p-5 font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider text-sm">
                                        Name
                                    </th>
                                    <th className="p-5 font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider text-sm">
                                        Slug
                                    </th>
                                    <th className="p-5 font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider text-sm">
                                        Type
                                    </th>
                                    <th className="p-5 font-bold text-gray-500 dark:text-gray-400 uppercase tracking-wider text-sm text-right">
                                        Actions
                                    </th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
                                {categories.map((c) => (
                                    <tr key={c._id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors">
                                        <td className="p-5">
                                            {c.image ? (
                                                <img src={c.image} alt={c.name} className="w-12 h-12 object-cover rounded-xl" />
                                            ) : (
                                                <div className="w-12 h-12 bg-gray-100 dark:bg-gray-800 rounded-xl flex items-center justify-center text-gray-400 text-xs text-center border dark:border-gray-700">
                                                    No Img
                                                </div>
                                            )}
                                        </td>
                                        <td className="p-5 font-black text-gray-900 dark:text-white">{c.name}</td>
                                        <td className="p-5 text-gray-500 dark:text-gray-400 font-medium">{c.slug}</td>
                                        <td className="p-5">
                                            <span
                                                className={`text-xs font-black uppercase px-3 py-1.5 rounded-lg inline-block ${c.type === "service"
                                                    ? "bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400"
                                                    : "bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400"
                                                    }`}
                                            >
                                                {c.type}
                                            </span>
                                        </td>
                                        <td className="p-5 text-right space-x-2">
                                            <button
                                                onClick={() => handleEdit(c)}
                                                className="text-sm px-3 py-1.5 bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 hover:bg-blue-100 dark:hover:bg-blue-900/50 rounded-lg font-bold transition-colors"
                                            >
                                                Edit
                                            </button>
                                            <button
                                                onClick={() => handleDelete(c._id)}
                                                className="text-sm px-3 py-1.5 bg-red-50 dark:bg-red-900/30 text-red-600 dark:text-red-400 hover:bg-red-100 dark:hover:bg-red-900/50 rounded-lg font-bold transition-colors"
                                            >
                                                Delete
                                            </button>
                                        </td>
                                    </tr>
                                ))}
                                {categories.length === 0 && (
                                    <tr>
                                        <td colSpan={5} className="p-10 text-center text-gray-500 dark:text-gray-400 font-medium">
                                            No categories found. Click Add Category to create one.
                                        </td>
                                    </tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { useState, useEffect } from "react";
import { Package, Truck, CheckCircle2, Clock, XCircle, ChevronDown, MapPin, Loader2 } from "lucide-react";
import { toast } from "sonner";
import Link from "next/link";

export default function AdminOrdersPage() {
    const [orders, setOrders] = useState<any[]>([]);
    const [riders, setRiders] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [updatingId, setUpdatingId] = useState<string | null>(null);

    const fetchOrders = () => {
        fetch("/api/orders")
            .then(res => res.json())
            .then(data => {
                if (data.success) {
                    setOrders(data.data);
                }
                setLoading(false);
            })
            .catch(() => setLoading(false));
    };

    const fetchRiders = () => {
        fetch("/api/admin/riders")
            .then(res => res.json())
            .then(data => {
                if (data.success) {
                    setRiders(data.data);
                }
            })
            .catch(() => {});
    };

    useEffect(() => {
        fetchOrders();
        fetchRiders();
    }, []);

    const handleRiderAssign = async (orderId: string, riderId: string) => {
        setUpdatingId(orderId);
        try {
            const res = await fetch(`/api/orders/${orderId}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ riderId })
            });
            const data = await res.json();

            if (data.success) {
                toast.success("Rider assigned!");
                fetchOrders();

                if (data.riderWhatsappUrl) {
                    window.open(data.riderWhatsappUrl, "_blank");
                }
            } else {
                toast.error(data.error || "Failed to assign rider");
            }
        } catch (error) {
            toast.error("An error occurred");
        } finally {
            setUpdatingId(null);
        }
    };

    const handleStatusUpdate = async (orderId: string, newStatus: string) => {
        setUpdatingId(orderId);
        try {
            const res = await fetch(`/api/orders/${orderId}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ status: newStatus })
            });
            const data = await res.json();

            if (data.success) {
                toast.success("Order status updated!");
                fetchOrders(); // Refresh table

                // Trigger WhatsApp redirect if available from backend
                if (data.whatsappRedirectUrl) {
                    window.open(data.whatsappRedirectUrl, "_blank");
                }
            } else {
                toast.error(data.error || "Failed to update status");
            }
        } catch (error) {
            toast.error("An error occurred");
        } finally {
            setUpdatingId(null);
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center p-12">
                <Loader2 className="w-8 h-8 animate-spin text-blue-600 dark:text-blue-400" />
            </div>
        );
    }

    return (
        <div>
            <div className="flex justify-between items-center mb-8">
                <div>
                    <h1 className="text-3xl font-black text-gray-900 dark:text-white">Manage Orders</h1>
                    <p className="text-gray-500 dark:text-gray-400 mt-2">Track and update customer delivery statuses.</p>
                </div>
                <div className="bg-blue-50 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400 px-4 py-2 rounded-xl font-bold flex items-center gap-2">
                    <Package className="w-5 h-5" /> {orders.length} Total
                </div>
            </div>

            <div className="bg-white dark:bg-gray-900 rounded-[2rem] shadow-sm border border-gray-100 dark:border-gray-800 overflow-hidden">
                <div className="overflow-x-auto">
                    <table className="w-full text-left border-collapse">
                        <thead>
                            <tr className="bg-gray-50 dark:bg-gray-800 border-b border-gray-100 dark:border-gray-700 text-xs uppercase tracking-widest text-gray-500 dark:text-gray-400">
                                <th className="p-4 pl-6 font-bold">Order Details</th>
                                <th className="p-4 font-bold hidden md:table-cell">Customer</th>
                                <th className="p-4 font-bold">Amount</th>
                                <th className="p-4 font-bold">Rider</th>
                                <th className="p-4 font-bold">Status Action</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100 dark:divide-gray-800">
                            {orders.length === 0 ? (
                                <tr>
                                    <td colSpan={4} className="p-12 text-center text-gray-500 dark:text-gray-400">
                                        No orders found.
                                    </td>
                                </tr>
                            ) : orders.map((order) => (
                                <tr key={order._id} className="hover:bg-gray-50/50 dark:hover:bg-gray-800/50 transition-colors group">
                                    <td className="p-4 pl-6 align-top">
                                        <div className="flex items-center gap-3 mb-2">
                                            <span className="text-xs font-black text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/30 px-2.5 py-1 rounded-lg">
                                                #{order._id.slice(-6).toUpperCase()}
                                            </span>
                                            <span className="text-xs font-bold text-gray-400 dark:text-gray-500">
                                                {new Date(order.createdAt).toLocaleDateString()}
                                            </span>
                                        </div>
                                        <div className="text-sm font-medium text-gray-900 dark:text-gray-100 line-clamp-2 pr-4">
                                            {order.type === 'service'
                                                ? <span className="text-purple-600 dark:text-purple-400 font-bold">{order.serviceCategory || "Service Request"}</span>
                                                : order.items?.map((i: any) => `${i.quantity}x ${i.name}`).join(", ") || "No items"}
                                        </div>
                                    </td>

                                    <td className="p-4 align-top hidden md:table-cell">
                                        <p className="font-bold text-gray-900 dark:text-white text-sm mb-1">{order.customerName}</p>
                                        <p className="text-xs text-gray-500 dark:text-gray-400 mb-2">{order.customerPhone}</p>
                                        <a
                                            href={`https://www.google.com/maps?q=${order.latitude},${order.longitude}`}
                                            target="_blank"
                                            referrerPolicy="no-referrer"
                                            className="inline-flex items-center gap-1 text-xs font-bold text-blue-600 dark:text-blue-400 hover:text-blue-800 dark:hover:text-blue-300 bg-blue-50 dark:bg-blue-900/30 px-2 py-1 rounded-md transition-colors"
                                        >
                                            <MapPin className="w-3 h-3" /> View Map
                                        </a>
                                    </td>

                                    <td className="p-4 align-top">
                                        <p className="font-black text-gray-900 dark:text-white">₹{order.total}</p>
                                        <div className="flex flex-col gap-1 mt-1">
                                            <span className="text-xs font-bold text-gray-600 dark:text-gray-300 bg-gray-100 dark:bg-gray-800 px-2 py-0.5 rounded-md self-start">
                                                {order.paymentMethod === 'upi' ? 'UPI' : 'COD'} {order.tipAmount ? `· ₹${order.tipAmount} Tip` : ''}
                                            </span>
                                            {order.transactionId && (
                                                <span className="text-[10px] text-gray-500 dark:text-gray-400 font-mono">
                                                    Txn: {order.transactionId}
                                                </span>
                                            )}
                                        </div>
                                    </td>

                                    <td className="p-4 align-top">
                                        <div className="relative inline-block w-40">
                                            <select
                                                value={order.riderId || ""}
                                                onChange={(e) => handleRiderAssign(order._id, e.target.value)}
                                                disabled={updatingId === order._id || ["delivered", "cancelled"].includes(order.status)}
                                                className="appearance-none w-full border border-gray-200 dark:border-gray-700 font-bold text-xs px-4 py-2.5 rounded-xl cursor-pointer outline-none transition-all disabled:opacity-50 bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-100 focus:ring-4 focus:ring-blue-100 dark:focus:ring-blue-900/50 focus:border-blue-500"
                                            >
                                                <option value="">Unassigned</option>
                                                {riders.map((rider) => (
                                                    <option key={rider._id} value={rider._id}>{rider.name}</option>
                                                ))}
                                            </select>
                                            <ChevronDown className="absolute right-3 top-2.5 w-4 h-4 text-gray-400 dark:text-gray-500 pointer-events-none" />
                                        </div>
                                        {order.deliveryStatus && (
                                            <p className="text-[10px] font-black uppercase text-blue-600 mt-1">
                                                {order.deliveryStatus.replace('_', ' ')}
                                            </p>
                                        )}
                                    </td>

                                    <td className="p-4 align-top">
                                        <div className="relative inline-block w-40">
                                            <select
                                                value={order.status}
                                                onChange={(e) => handleStatusUpdate(order._id, e.target.value)}
                                                disabled={updatingId === order._id}
                                                className={`appearance-none w-full border font-bold text-xs px-4 py-2.5 rounded-xl cursor-pointer outline-none transition-all disabled:opacity-50
                                                    ${order.status === 'delivered' ? 'bg-green-50 dark:bg-green-900/30 border-green-200 dark:border-green-800 text-green-700 dark:text-green-400 focus:ring-green-100 dark:focus:ring-green-900' :
                                                        order.status === 'cancelled' ? 'bg-red-50 dark:bg-red-900/30 border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 focus:ring-red-100 dark:focus:ring-red-900' :
                                                            'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-900 dark:text-gray-100 focus:ring-4 focus:ring-blue-100 dark:focus:ring-blue-900/50 focus:border-blue-500 dark:focus:border-blue-500 hover:bg-gray-50 dark:hover:bg-gray-700'}
                                                `}
                                            >
                                                <option value="pending" className="bg-white dark:bg-gray-800 text-gray-900 dark:text-white">🟡 Pending</option>
                                                <option value="processing" className="bg-white dark:bg-gray-800 text-gray-900 dark:text-white">📦 Processing</option>
