        await connectToDatabase();
        const order = await Order.findById(resolvedParams.id);

        if (!order) {
            return NextResponse.json({ success: false, error: "Order not found" }, { status: 404 });
        }

        return NextResponse.json({ success: true, data: order });
    } catch (error: any) {
        return NextResponse.json({ success: false, error: error.message }, { status: 500 });
    }
}

// DELETE: User cancels their own pending order
export async function DELETE(req: Request, { params }: { params: Promise<{ id: string }> }) {
    try {
        const resolvedParams = await params;
        const session = await getServerSession(authOptions);

        if (!session?.user) {
            return NextResponse.json({ success: false, error: "Unauthorized" }, { status: 401 });
        }

        await connectToDatabase();

        const order = await Order.findById(resolvedParams.id);
        if (!order) {
            return NextResponse.json({ success: false, error: "Order not found" }, { status: 404 });
        }

        // Only order owner or admin can cancel
        if (order.userId !== session.user.id && session.user.role !== "admin") {
            return NextResponse.json({ success: false, error: "Forbidden" }, { status: 403 });
        }

        // Only allow cancel if still pending
        if (order.status !== "pending") {
            return NextResponse.json({ 
                success: false, 
                error: "Order can only be cancelled when it is pending" 
            }, { status: 400 });
        }

        order.status = "cancelled";
        order.deliveryStatus = "cancelled";
        await order.save();

        return NextResponse.json({ success: true, data: order });
    } catch (error: any) {
        return NextResponse.json({ success: false, error: error.message }, { status: 500 });
    }
}

export async function PATCH(req: Request, { params }: { params: Promise<{ id: string }> }) {
    try {
        const resolvedParams = await params;
        const session = await getServerSession(authOptions);

        if (!session || session.user.role !== "admin") {
            return NextResponse.json({ success: false, error: "Unauthorized" }, { status: 401 });
        }

        const { status, riderId, deliveryStatus } = await req.json();

        // Validate Status Enum if provided
        if (status) {
            const validStatuses = ["pending", "processing", "shipped", "delivered", "cancelled"];
            if (!validStatuses.includes(status)) {
                return NextResponse.json({ success: false, error: "Invalid status" }, { status: 400 });
            }
        }

        await connectToDatabase();

        const updateData: any = {};
        if (status) updateData.status = status;
        if (riderId) {
            updateData.riderId = riderId;
            updateData.deliveryStatus = "assigned";
        }
        if (deliveryStatus) updateData.deliveryStatus = deliveryStatus;

        const updatedOrder = await Order.findByIdAndUpdate(
            resolvedParams.id,
            updateData,
            { new: true }
        );

        if (!updatedOrder) {
            return NextResponse.json({ success: false, error: "Order not found" }, { status: 404 });
        }

        let whatsappRedirectUrl = null;
        let riderWhatsappUrl = null;

        // Notify Rider if assigned
        if (riderId) {
            const rider = await User.findById(riderId);
            if (rider && rider.whatsapp) {
                const orderId = updatedOrder._id.toString().slice(-6).toUpperCase();
                const riderMsg = `Hi ${rider.name}, you have been assigned a new Localu order #${orderId}. Please visit your dashboard to accept: ${process.env.NEXTAUTH_URL}/rider`;
                const cleanRiderPhone = rider.whatsapp.replace(/\D/g, '');
                const finalRiderPhone = cleanRiderPhone.length === 10 ? `91${cleanRiderPhone}` : cleanRiderPhone;
                riderWhatsappUrl = `https://wa.me/${finalRiderPhone}?text=${encodeURIComponent(riderMsg)}`;
            }
        }

        if (["processing", "shipped", "delivered"].includes(status) && updatedOrder.customerPhone) {
            let message = "";
            const orderId = updatedOrder._id.toString().slice(-6).toUpperCase();

            if (status === "processing") {
                message = `Hi ${updatedOrder.customerName}, your Localu order #${orderId} is now being processed. We will notify you once it's shipped!`;
            } else if (status === "shipped") {
                message = `Hi ${updatedOrder.customerName}, your Localu order #${orderId} has been shipped and is on its way to you!`;
            } else if (status === "delivered") {
                message = `Hi ${updatedOrder.customerName}, your Localu order #${orderId} has been delivered. Thank you for shopping with us!`;
            }

            const cleanPhone = updatedOrder.customerPhone.replace(/\D/g, ''); // Remove non-digits
            // Assuming Indian numbers default if no country code
            const finalPhone = cleanPhone.length === 10 ? `91${cleanPhone}` : cleanPhone;

            whatsappRedirectUrl = `https://wa.me/${finalPhone}?text=${encodeURIComponent(message)}`;

            // Mock Email / Push Notification Dispatch
            console.info(`[Notification] Order Update for #${orderId} - User: ${updatedOrder.customerName}. Message: ${message}`);
            // if (process.env.RESEND_API_KEY) { await resend.emails.send({...}) }
        }

        return NextResponse.json({ success: true, data: updatedOrder, whatsappRedirectUrl, riderWhatsappUrl }, { status: 200 });

    } catch (error: any) {
        return NextResponse.json({ success: false, error: error.message }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import connectToDatabase from "@/lib/mongoose";
import Order from "@/models/Order";
import User from "@/models/User";
import { getServerSession } from "next-auth/next";
import { authOptions } from "@/app/api/auth/[...nextauth]/route";
import { requireUser } from "@/lib/routeAuth";

export async function POST(request: Request) {
    try {
        await connectToDatabase();
        const body = await request.json();
        const session = await getServerSession(authOptions);

        if (session?.user?.id) {
            body.userId = session.user.id;
        }

        const { type, customerName, customerPhone, address, latitude, longitude, tipAmount } = body;

        let subtotal = 0;
        const deliveryFee = 30;
        const platformFee = 5;
        let tax = 0;

        let whatsappText = "";

        if (type === "product") {
            const { items } = body;
            items.forEach((item: any) => {
                subtotal += item.price * item.quantity;
            });
            tax = subtotal * 0.05;

            const total = subtotal + deliveryFee + platformFee + tax + (tipAmount || 0);

            body.subtotal = subtotal;
            body.deliveryFee = deliveryFee;
            body.platformFee = platformFee;
            body.tax = tax;
            body.tipAmount = tipAmount || 0;
            body.total = total;

            whatsappText = `New Product Order:
--------------------------------
${items.map((i: any) => `${i.name} x ${i.quantity} = ₹${i.price * i.quantity}`).join("\n")}
--------------------------------
Subtotal: ₹${subtotal.toFixed(2)}
Delivery Fee: ₹${deliveryFee}
Platform Fee: ₹${platformFee}
Tax: ₹${tax.toFixed(2)}
${body.discountAmount ? `Discount (-): ₹${body.discountAmount.toFixed(2)}\n` : ''}${body.walletUsed ? `Wallet Applied (-): ₹${body.walletUsed.toFixed(2)}\n` : ''}${body.tipAmount ? `Rider Tip (+): ₹${body.tipAmount.toFixed(2)}\n` : ''}Total: ₹${body.total.toFixed(2)}
--------------------------------
Customer: ${customerName}
Phone: ${customerPhone}
Address: ${address}
Google Maps: https://www.google.com/maps?q=${latitude},${longitude}`;
        } else if (type === "service") {
            const { serviceCategory, serviceDetails } = body;

            // Mock dynamic pricing logic
            if (serviceCategory === "Petrol Delivery") {
                subtotal = (serviceDetails.quantity || 1) * 105; // Mock 105 per liter
            } else if (serviceCategory === "Pickup & Drop") {
                subtotal = 150; // Mock base rate
            } else {
                subtotal = 200;
            }

            tax = subtotal * 0.05;
            const total = subtotal + deliveryFee + platformFee + tax + (tipAmount || 0);

            body.subtotal = subtotal;
            body.deliveryFee = deliveryFee;
            body.platformFee = platformFee;
            body.tax = tax;
            body.tipAmount = tipAmount || 0;
            body.total = total;

            const detailsText = Object.entries(serviceDetails || {})
                .map(([k, v]) => `${k}: ${v}`)
                .join("\n");

            whatsappText = `New Service Request:
--------------------------------
Service Type: ${serviceCategory}
Details:
${detailsText}
--------------------------------
Estimated Price: ₹${total.toFixed(2)}
${body.tipAmount ? `Rider Tip (+): ₹${body.tipAmount.toFixed(2)}\n` : ''}--------------------------------
Customer: ${customerName}
Phone: ${customerPhone}
Address: ${address}
Google Maps: https://www.google.com/maps?q=${latitude},${longitude}`;
        }

        const order = await Order.create({
            type,
            userId: body.userId,
            items: body.items,
            serviceCategory: body.serviceCategory,
            serviceDetails: body.serviceDetails,
            status: "pending",
            subtotal: body.subtotal,
            deliveryFee: body.deliveryFee,
            platformFee: body.platformFee,
            tax: body.tax,
            discountAmount: body.discountAmount || 0,
            promoCode: body.promoCode,
            walletUsed: body.walletUsed || 0,
            total: body.total,
            tipAmount: body.tipAmount || 0,
            paymentMethod: body.paymentMethod || "cod",
            transactionId: body.transactionId,
            customerName,
            customerPhone,
            address,
            latitude,
            longitude,
            deliveryStatus: "pending",
        });

        const finalWhatsappText = whatsappText +
            `\n--------------------------------
Payment: ${(body.paymentMethod || "cod").toUpperCase()}
${body.transactionId ? `Txn ID: ${body.transactionId}\n` : ''}--------------------------------
Order Tracking ID: #${order._id.toString().slice(-6).toUpperCase()}`;

        const ownerNumber = process.env.OWNER_NUMBER || "917659989336";
        const encodedMessage = encodeURIComponent(finalWhatsappText);
        const redirectUrl = `https://wa.me/${ownerNumber}?text=${encodedMessage}`;

        // Deduct Wallet Balance if used
        if (body.walletUsed && body.userId) {
            await User.findByIdAndUpdate(body.userId, {
                $inc: { walletBalance: -body.walletUsed }
            });
