import { NextResponse } from "next/server";
import connectToDatabase from "@/lib/mongoose";
import Product from "@/models/Product";

export async function GET(request: Request) {
    try {
        const { searchParams } = new URL(request.url);
        const query = searchParams.get("q");
        const limit = parseInt(searchParams.get("limit") || "10");
        const minPrice = searchParams.get("minPrice");
        const maxPrice = searchParams.get("maxPrice");
        const sort = searchParams.get("sort");

        await connectToDatabase();

        let dbQuery: any = {};

        if (query) {
            const searchRegex = new RegExp(query, "i");
            dbQuery.$or = [
                { name: searchRegex },
                { categorySlug: searchRegex }
            ];
        }

        if (minPrice || maxPrice) {
            dbQuery.price = {};
            if (minPrice) dbQuery.price.$gte = Number(minPrice);
            if (maxPrice) dbQuery.price.$lte = Number(maxPrice);
        }

        let sortOption: any = { createdAt: -1 };
        if (sort === 'price_asc') sortOption = { price: 1 };
        if (sort === 'price_desc') sortOption = { price: -1 };

        const products = await Product.find(dbQuery).sort(sortOption).limit(limit).lean();

        return NextResponse.json({ success: true, data: products });
    } catch (error) {
        return NextResponse.json(
            { success: false, error: "Failed to search products" },
            { status: 400 }
        );
    }
}

import { NextResponse } from "next/server";
import connectToDatabase from "@/lib/mongoose";
import PromoCode from "@/models/PromoCode";

export async function POST(req: Request) {
    try {
        const { code, cartTotal } = await req.json();

        if (!code || typeof cartTotal !== 'number') {
            return NextResponse.json({ success: false, error: "Invalid request" }, { status: 400 });
        }

        await connectToDatabase();

        const promo = await PromoCode.findOne({
            code: code.toUpperCase(),
            isActive: true
        });

        if (!promo) {
            return NextResponse.json({ success: false, error: "Invalid or inactive promo code" }, { status: 404 });
        }

        // Check Expiry
        if (promo.expiresAt && new Date(promo.expiresAt) < new Date()) {
            return NextResponse.json({ success: false, error: "Promo code has expired" }, { status: 400 });
        }

        // Check Usage Limit
        if (promo.usageLimit && promo.usedCount >= promo.usageLimit) {
            return NextResponse.json({ success: false, error: "Promo code usage limit reached" }, { status: 400 });
        }

        // Check Minimum Order Amount
        if (cartTotal < promo.minOrderAmount) {
            return NextResponse.json({
                success: false,
                error: `Minimum order amount of ₹${promo.minOrderAmount} required`
            }, { status: 400 });
        }

        // Calculate Discount
        let discountAmount = 0;
        if (promo.discountType === "fixed") {
            discountAmount = promo.discountValue;
        } else if (promo.discountType === "percentage") {
            discountAmount = (cartTotal * promo.discountValue) / 100;
        }

        // Ensure discount doesn't exceed cart total
        discountAmount = Math.min(discountAmount, cartTotal);

        // ✅ Bug Fix: Increment usedCount so usage limits are enforced
        await PromoCode.findByIdAndUpdate(promo._id, { $inc: { usedCount: 1 } });

        return NextResponse.json({
            success: true,
            data: {
                code: promo.code,
                discountAmount: Number(discountAmount.toFixed(2)),
                message: `Promo code applied successfully!`
            }
        }, { status: 200 });

    } catch (error: any) {
        return NextResponse.json({ success: false, error: error.message }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import connectToDatabase from "@/lib/mongoose";
import Review from "@/models/Review";

// POST { productIds: string[] } → returns avg rating + count per productId
export async function POST(req: Request) {
    try {
        const { productIds } = await req.json();

        if (!Array.isArray(productIds) || productIds.length === 0) {
            return NextResponse.json({ success: true, data: [] });
        }

        await connectToDatabase();

        // Aggregate average rating per productId
        // Reviews are linked to orders; for product-level display we treat all 
        // reviews for orders containing a productId via Review.productId field.
        // If productId is not set on review, we show order-level reviews by orderId.
        // Here we aggregate by orderId as a proxy (per-category).
        const pipeline = [
            { $match: { productId: { $in: productIds } } },
            {
                $group: {
                    _id: "$productId",
                    avgRating: { $avg: "$rating" },
                    count: { $sum: 1 },
                }
            }
        ];

        const results = await Review.aggregate(pipeline);

        const data = results.map((r: any) => ({
            productId: r._id,
            avgRating: Math.round(r.avgRating * 10) / 10,
            count: r.count,
        }));

        return NextResponse.json({ success: true, data });
    } catch (error: any) {
        return NextResponse.json({ success: false, error: error.message }, { status: 500 });
    }
}

import { NextResponse } from "next/server";
import connectToDatabase from "@/lib/mongoose";
import Review from "@/models/Review";
import Order from "@/models/Order";
