"use client";

import { useEffect, useState } from "react";
import { useCart } from "@/context/CartContext";
import { Plus, Minus, ShoppingCart, Heart, Star } from "lucide-react";
import Image from "next/image";
import * as motion from "framer-motion/client";
import { toast } from "sonner";
import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";

export default function ProductListing({ categorySlug }: { categorySlug: string }) {
    const [products, setProducts] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [wishlistItems, setWishlistItems] = useState<string[]>([]);
    const [ratings, setRatings] = useState<Record<string, { avgRating: number; count: number }>>({});
    const { cart, addToCart, updateQuantity } = useCart();
    const { data: session } = useSession();
    const router = useRouter();

    useEffect(() => {
        fetch(`/api/products?categorySlug=${categorySlug}`)
            .then((res) => res.json())
            .then(async (data) => {
                if (data.success) {
                    setProducts(data.data);

                    // Fetch ratings for all products in one batch request
                    const ids = data.data.map((p: any) => p._id).filter(Boolean);
                    if (ids.length > 0) {
                        try {
                            const rRes = await fetch("/api/reviews/ratings", {
                                method: "POST",
                                headers: { "Content-Type": "application/json" },
                                body: JSON.stringify({ productIds: ids }),
                            });
                            const rData = await rRes.json();
                            if (rData.success && rData.data.length > 0) {
                                const map: Record<string, { avgRating: number; count: number }> = {};
                                rData.data.forEach((r: any) => {
                                    map[r.productId] = { avgRating: r.avgRating, count: r.count };
                                });
                                setRatings(map);
                            }
                        } catch {
                            // Ratings are non-critical, ignore fetch errors
                        }
                    }
                }
                setLoading(false);
            });
    }, [categorySlug]);

    useEffect(() => {
        if (session) {
            fetch('/api/wishlist')
                .then(res => res.json())
                .then(data => {
                    if (data.success) setWishlistItems(data.data);
                });
        }
    }, [session]);

    const toggleWishlist = async (productId: string) => {
        if (!session) {
            toast.error("Please login to add to wishlist.");
            router.push("/login");
            return;
        }

        const isWished = wishlistItems.includes(productId);
        setWishlistItems(prev => isWished ? prev.filter(id => id !== productId) : [...prev, productId]);

        try {
            const res = await fetch("/api/wishlist", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ productId })
            });
            const data = await res.json();
            if (!data.success) {
                setWishlistItems(prev => isWished ? [...prev, productId] : prev.filter(id => id !== productId));
                toast.error(data.error || "Failed to update wishlist");
            }
        } catch (e) {
            setWishlistItems(prev => isWished ? [...prev, productId] : prev.filter(id => id !== productId));
            toast.error("Error updating wishlist");
        }
    };

    if (loading)
        return (
            <div className="py-20 text-center text-gray-500 animate-pulse font-medium">
                Loading products...
            </div>
        );

    if (products.length === 0) {
        return (
            <div className="py-20 flex flex-col items-center justify-center text-gray-500 dark:text-gray-400 bg-white dark:bg-gray-900 rounded-3xl border border-dashed border-gray-300 dark:border-gray-700 shadow-sm">
                <ShoppingCart className="w-16 h-16 mb-4 text-gray-200 dark:text-gray-700" />
                <p className="font-medium text-lg">No products found here.</p>
                <p className="text-sm mt-1">Check back later for new arrivals.</p>
            </div>
        );
    }

    return (
        <motion.div
            className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 sm:gap-8"
            initial="hidden"
            animate="show"
            variants={{
                hidden: { opacity: 0 },
                show: {
                    opacity: 1,
                    transition: { staggerChildren: 0.1 }
                }
            }}
        >
            {products.map((product, idx) => {
                const cartItem = cart.find((i) => i.productId === product._id);
                const isPremium = idx % 3 === 0;
                const rating = ratings[product._id];

                return (
                    <motion.div
                        key={product._id}
                        variants={{
                            hidden: { opacity: 0, y: 30 },
                            show: { opacity: 1, y: 0, transition: { type: "spring", stiffness: 300, damping: 25 } }
                        }}
                        className="group flex flex-col bg-white/50 dark:bg-slate-900/50 glass-card rounded-[2rem] overflow-hidden premium-shadow hover:-translate-y-2 transition-all duration-500"
                    >
                        <div className="relative w-full aspect-[4/3] overflow-hidden">
                            {isPremium && (
                                <div className="absolute top-4 left-4 z-10 px-3 py-1 bg-amber-500 text-white text-[10px] font-black uppercase tracking-widest rounded-full shadow-lg animate-pulse-soft">
                                    Best Value
                                </div>
                            )}
                            <button
                                onClick={(e) => { e.preventDefault(); e.stopPropagation(); toggleWishlist(product._id); }}
                                className="absolute top-4 right-4 z-10 p-2.5 bg-white/90 dark:bg-slate-950/90 backdrop-blur-xl rounded-full hover:scale-110 active:scale-90 transition-all shadow-lg border border-white/20"
                            >
                                <Heart className={`w-5 h-5 ${wishlistItems.includes(product._id) ? 'fill-red-500 text-red-500' : 'text-slate-400'}`} />
                            </button>
                            {product.image ? (
                                <Image
                                    src={product.image}
                                    alt={product.name}
                                    fill
                                    className="object-cover transition-transform duration-1000 group-hover:scale-110"
                                    sizes="(max-width: 768px) 100vw, (max-width: 1200px) 50vw, 33vw"
                                />
                            ) : (
                                <div className="w-full h-full flex items-center justify-center bg-slate-100 dark:bg-slate-800">
                                    <ShoppingCart className="w-16 h-16 text-slate-200 dark:text-slate-700" />
                                </div>
                            )}
                            <div className="absolute inset-0 bg-gradient-to-t from-slate-950/40 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-500" />
                        </div>

                        <div className="p-6 md:p-8 flex flex-col h-full">
                            <div className="mb-4">
                                <h3 className="font-black text-xl md:text-2xl text-slate-900 dark:text-white leading-tight mb-1 group-hover:text-blue-600 dark:group-hover:text-blue-400 transition-colors">
                                    {product.name}
                                </h3>

                                {/* ✅ Feature: Product Description */}
                                {product.description && (
                                    <p className="text-xs text-slate-500 dark:text-slate-400 font-medium leading-relaxed mb-2 line-clamp-2">
                                        {product.description}
                                    </p>
                                )}

                                <div className="flex items-center gap-2 flex-wrap">
                                    <span className="text-xs font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest px-2 py-0.5 bg-slate-100 dark:bg-slate-800 rounded">
                                        {product.unit}
                                    </span>
                                    {product.inStock && (
                                        <span className="text-[10px] font-black text-emerald-500 uppercase tracking-widest flex items-center gap-1">
                                            <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse" /> In Stock
                                        </span>
                                    )}
                                    {/* ✅ Feature: Average Rating */}
                                    {rating && rating.count > 0 && (
                                        <span className="flex items-center gap-1 text-[10px] font-black text-amber-500 uppercase tracking-widest">
                                            <Star className="w-3 h-3 fill-amber-500" />
                                            {rating.avgRating} ({rating.count})
                                        </span>
                                    )}
                                </div>
                            </div>

                            <div className="mt-auto flex items-center justify-between gap-4 pt-6 border-t border-slate-100 dark:border-slate-800">
                                <div className="flex flex-col">
                                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Price</span>
                                    <span className="font-black text-2xl md:text-3xl text-slate-900 dark:text-white">
                                        ₹{product.price}
                                    </span>
                                </div>

                                {!product.inStock ? (
                                    <span className="px-5 py-2.5 rounded-2xl bg-slate-100 dark:bg-slate-800 text-slate-400 text-xs font-black uppercase tracking-widest">
                                        Sold Out
                                    </span>
                                ) : cartItem ? (
                                    <div className="flex items-center gap-3 bg-slate-900 dark:bg-white text-white dark:text-slate-900 rounded-2xl p-1.5 shadow-xl shadow-slate-900/20">
                                        <motion.button
                                            whileTap={{ scale: 0.8 }}
                                            onClick={() => updateQuantity(product._id, cartItem.quantity - 1)}
                                            className="p-1.5 hover:bg-white/10 dark:hover:bg-slate-900/10 rounded-xl transition-colors"
                                        >
                                            <Minus className="w-5 h-5" />
                                        </motion.button>
                                        <span className="w-8 text-center font-black text-lg">
                                            {cartItem.quantity}
                                        </span>
                                        <motion.button
                                            whileTap={{ scale: 0.8 }}
                                            onClick={() => updateQuantity(product._id, cartItem.quantity + 1)}
                                            className="p-1.5 hover:bg-white/10 dark:hover:bg-slate-900/10 rounded-xl transition-colors"
                                        >
                                            <Plus className="w-5 h-5" />
                                        </motion.button>
                                    </div>
                                ) : (
                                    <motion.button
                                        whileHover={{ scale: 1.05 }}
                                        whileTap={{ scale: 0.95 }}
                                        onClick={() => {
                                            if (!session) {
                                                toast.error("Please login to order products.");
                                                router.push("/login");
                                                return;
                                            }
                                            addToCart({
                                                productId: product._id,
                                                name: product.name,
                                                price: product.price,
                                                quantity: 1,
                                            });
                                            toast.success(`${product.name} added`, {
                                                style: { borderRadius: '1rem', border: 'none', background: '#0f172a', color: '#fff' }
                                            });
                                        }}
                                        className="px-8 py-3.5 bg-blue-600 text-white font-black rounded-2xl shadow-lg shadow-blue-500/30 hover:bg-blue-700 hover:shadow-blue-500/50 transition-all uppercase tracking-widest text-xs"
                                    >
                                        Add to Cart
                                    </motion.button>
                                )}
                            </div>
                        </div>
                    </motion.div>
                );
            })}
        </motion.div>
    );
}

"use client";

import { useState, useEffect, useRef } from "react";
import { Search, Loader2, Store } from "lucide-react";
import { useRouter } from "next/navigation";
import Image from "next/image";
import Link from "next/link";

export default function SearchBar() {
    const [query, setQuery] = useState("");
    const [results, setResults] = useState<any[]>([]);
    const [loading, setLoading] = useState(false);
    const [isOpen, setIsOpen] = useState(false);
    const router = useRouter();
    const wrapperRef = useRef<HTMLFormElement>(null);

    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
                setIsOpen(false);
            }
        };
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, []);

    useEffect(() => {
        const fetchResults = async () => {
            if (!query.trim()) {
                setResults([]);
                setIsOpen(false);
                return;
            }
            setLoading(true);
            try {
                const res = await fetch(`/api/products/search?q=${encodeURIComponent(query)}&limit=5`);
                const data = await res.json();
                if (data.success) {
                    setResults(data.data);
                    setIsOpen(true);
                }
            } catch (e) {
                // Ignore
            } finally {
                setLoading(false);
            }
        };

        const timeoutId = setTimeout(fetchResults, 300);
        return () => clearTimeout(timeoutId);
    }, [query]);

    const handleSearch = (e: React.FormEvent) => {
        e.preventDefault();
        setIsOpen(false);
        if (query.trim()) {
            router.push(`/search?q=${encodeURIComponent(query.trim())}`);
        }
    };

    return (
        <form
            ref={wrapperRef}
            onSubmit={handleSearch}
            className="relative w-full max-w-2xl mx-auto flex items-center z-50"
        >
            <div className="absolute left-3 sm:left-4 text-gray-400 dark:text-gray-500">
                <Search className="w-4 h-4 sm:w-5 sm:h-5" />
            </div>
            <input
                type="text"
                placeholder="Search products..."
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                className="w-full bg-white/20 dark:bg-slate-900/40 backdrop-blur-3xl text-slate-900 dark:text-white border border-white/20 dark:border-slate-800/50 rounded-[2.5rem] py-3.5 sm:py-6 pl-10 sm:pl-14 pr-14 sm:pr-36 focus:outline-none focus:ring-4 sm:focus:ring-8 focus:ring-blue-100/50 dark:focus:ring-blue-900/20 focus:border-blue-500/50 transition-all font-black shadow-2xl hover:shadow-blue-500/10 placeholder:text-slate-400 placeholder:italic placeholder:font-bold tracking-tight text-sm sm:text-base"
            />
            <button
                type="submit"
                className="absolute right-2 sm:right-3 top-2 sm:top-3 bottom-2 sm:bottom-3 bg-slate-900 dark:bg-white text-white dark:text-slate-900 font-black px-6 sm:px-10 rounded-[1.25rem] sm:rounded-[1.5rem] transition-all hover:scale-95 active:scale-90 hidden sm:block shadow-lg uppercase tracking-widest text-[10px]"
            >
                Search
            </button>
            <button
                type="submit"
                className="absolute right-2 top-2 bottom-2 bg-slate-900 dark:bg-white text-white dark:text-slate-900 font-black px-3.5 rounded-[1rem] transition-all hover:scale-95 active:scale-90 sm:hidden shadow-lg"
            >
                <Search className="w-4 h-4" />
            </button>

            {/* Dropdown Auto-suggest */}
            {isOpen && query.trim() !== "" && (
                <div className="absolute top-[calc(100%+12px)] left-0 right-0 bg-white/40 dark:bg-slate-900/40 backdrop-blur-3xl rounded-[2.5rem] shadow-2xl border border-white/20 dark:border-slate-800/50 overflow-hidden z-50 animate-in fade-in slide-in-from-top-4 duration-300">
                    <div className="p-4 bg-slate-50/50 dark:bg-slate-950/20 border-b border-white/10">
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] ml-2">Recommended for you</p>
                    </div>
                    {loading ? (
                        <div className="flex items-center justify-center p-12 text-blue-600">
                            <Loader2 className="w-8 h-8 animate-spin" />
                        </div>
                    ) : results.length > 0 ? (
                        <ul className="max-h-[30rem] overflow-y-auto p-4 space-y-2">
                            {results.map((product) => (
                                <li key={product._id}>
                                    <Link
                                        href={`/search?q=${encodeURIComponent(product.name)}`}
                                        onClick={() => setIsOpen(false)}
                                        className="flex items-center gap-6 p-4 hover:bg-white/40 dark:hover:bg-slate-800/40 rounded-[1.5rem] transition-all group border border-transparent hover:border-white/20 dark:hover:border-slate-700/30"
                                    >
                                        <div className="relative w-16 h-16 bg-white dark:bg-slate-800 rounded-2xl overflow-hidden flex-shrink-0 shadow-lg group-hover:scale-110 transition-transform">
                                            {product.image ? (
                                                <Image src={product.image} alt={product.name} fill className="object-cover" />
                                            ) : (
                                                <Store className="w-8 h-8 m-auto mt-4 text-slate-200 dark:text-slate-600" />
                                            )}
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <p className="text-lg font-black text-slate-900 dark:text-white truncate tracking-tight">{product.name}</p>
                                            <div className="flex items-center gap-2 mt-1">
                                                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{product.unit || 'Standard'}</span>
                                            </div>
                                        </div>
                                        <div className="text-xl font-black text-slate-900 dark:text-white">
                                            <span className="text-blue-600 text-sm italic mr-1">₹</span>{product.price}
                                        </div>
                                    </Link>
                                </li>
                            ))}
                            <li className="pt-4 px-2">
                                <button type="submit" className="w-full bg-slate-900 dark:bg-white text-white dark:text-slate-900 h-14 rounded-2xl font-black uppercase tracking-[0.2em] text-[10px] hover:opacity-90 transition-all shadow-md">
                                    View all results for "{query}"
                                </button>
                            </li>
                        </ul>
                    ) : (
                        <div className="p-16 text-center space-y-4">
                            <div className="w-16 h-16 bg-slate-100 dark:bg-slate-800 rounded-full flex items-center justify-center mx-auto mb-4">
                                <Search className="w-8 h-8 text-slate-300" />
                            </div>
                            <p className="text-sm font-black text-slate-400 uppercase tracking-widest">
                                No products found matching <br/>
                                <span className="text-slate-900 dark:text-white italic">"{query}"</span>
                            </p>
                        </div>
                    )}
                </div>
            )}
        </form>
    );
}

"use client";

import { useState } from "react";
import { getCurrentLocation } from "@/lib/geolocation";
import { Loader2, MapPin } from "lucide-react";
import { useSession } from "next-auth/react";

export default function ServiceForm({ categoryName }: { categoryName: string }) {
    const { data: session } = useSession();
    const [loading, setLoading] = useState(false);
    const [formData, setFormData] = useState<any>({});
    const [customer, setCustomer] = useState({ name: "", phone: "", address: "" });
    const [error, setError] = useState("");

    const handleServiceChange = (
        e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
    ) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleCustomerChange = (
        e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
    ) => {
        setCustomer({ ...customer, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        setError("");

        try {
            const location = await getCurrentLocation();

            const payload = {
                type: "service",
                userId: (session as any)?.user?.id,
                serviceCategory: categoryName,
                serviceDetails: formData,
                customerName: customer.name,
                customerPhone: customer.phone,
                address: customer.address,
                latitude: location.latitude,
                longitude: location.longitude,
            };

            const res = await fetch("/api/orders", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(payload),
            });

            const data = await res.json();
            if (!data.success) throw new Error(data.error);

            window.location.href = data.redirectUrl;
        } catch (err: any) {
            setError(err.message || "Please ensure location is enabled and try again.");
            setLoading(false);
        }
    };

    const renderFields = () => {
        const slug = categoryName.toLowerCase();

        if (slug.includes("petrol") || slug.includes("fuel")) {
            return (
                <>
                    <div>
                        <label className="block text-sm font-semibold mb-2 text-gray-700">
                            Fuel Type
                        </label>
                        <div className="flex gap-4">
                            <label className="flex items-center gap-2 cursor-pointer border p-4 rounded-2xl flex-1 hover:bg-gray-50 transition-colors border-gray-200">
                                <input
                                    type="radio"
                                    name="fuelType"
                                    value="Petrol"
                                    onChange={handleServiceChange}
                                    required
                                    className="w-4 h-4 text-purple-600"
                                />
                                <span className="font-bold text-gray-900">Petrol</span>
                            </label>
                            <label className="flex items-center gap-2 cursor-pointer border p-4 rounded-2xl flex-1 hover:bg-gray-50 transition-colors border-gray-200">
                                <input
                                    type="radio"
                                    name="fuelType"
                                    value="Diesel"
                                    onChange={handleServiceChange}
                                    required
                                    className="w-4 h-4 text-purple-600"
                                />
                                <span className="font-bold text-gray-900">Diesel</span>
                            </label>
                        </div>
                    </div>
                    <div className="mt-4">
                        <label className="block text-sm font-semibold mb-2 text-gray-700">
                            Quantity (Liters)
                        </label>
                        <input
                            type="number"
                            name="quantity"
                            min="1"
                            onChange={handleServiceChange}
                            required
                            className="w-full border border-gray-200 p-4 rounded-2xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 outline-none transition-all font-medium text-gray-900"
                            placeholder="e.g. 5"
                        />
                    </div>
                </>
            );
        }

        if (slug.includes("pickup") || slug.includes("drop")) {
            return (
                <>
                    <div className="space-y-4">
                        <div>
                            <label className="block text-sm font-semibold mb-2 text-gray-700">
                                Pickup Location Details
                            </label>
                            <input
                                type="text"
                                name="pickupLocation"
                                onChange={handleServiceChange}
                                required
                                className="w-full border border-gray-200 p-4 rounded-2xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 outline-none transition-all font-medium"
                                placeholder="e.g. 123 Main St, Apartment 4B"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-semibold mb-2 text-gray-700">
                                Drop Location Details
                            </label>
                            <input
                                type="text"
                                name="dropLocation"
                                onChange={handleServiceChange}
                                required
                                className="w-full border border-gray-200 p-4 rounded-2xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 outline-none transition-all font-medium"
                                placeholder="e.g. 456 Elm St, Gate 2"
                            />
                        </div>
                        <div>
                            <label className="block text-sm font-semibold mb-2 text-gray-700">
                                Item Description & Urgency
                            </label>
                            <textarea
                                name="itemDescription"
                                onChange={handleServiceChange}
                                required
                                className="w-full border border-gray-200 p-4 rounded-2xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 outline-none transition-all h-28 font-medium"
                                placeholder="What are we picking up? How urgent is it?"
                            />
                        </div>
                    </div>
                </>
            );
        }

        if (slug.includes("event") || slug.includes("party")) {
            return (
                <div className="space-y-4">
                    <div>
                        <label className="block text-sm font-semibold mb-2 text-gray-700">
                            Event Type
                        </label>
                        <input
                            type="text"
                            name="eventType"
                            onChange={handleServiceChange}
                            required
                            className="w-full border border-gray-200 p-4 rounded-2xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 outline-none transition-all font-medium"
                            placeholder="e.g. Birthday Party, Corporate Setup"
                        />
                    </div>
                    <div className="flex gap-4">
                        <div className="flex-1">
                            <label className="block text-sm font-semibold mb-2 text-gray-700">
                                Date
                            </label>
                            <input
                                type="date"
                                name="eventDate"
                                onChange={handleServiceChange}
                                required
                                className="w-full border border-gray-200 p-4 rounded-2xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 outline-none transition-all font-medium"
                            />
                        </div>
                        <div className="flex-1">
                            <label className="block text-sm font-semibold mb-2 text-gray-700">
                                Guests
                            </label>
                            <input
                                type="number"
                                name="peopleCount"
                                onChange={handleServiceChange}
                                required
                                className="w-full border border-gray-200 p-4 rounded-2xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 outline-none transition-all font-medium"
                                placeholder="100"
                            />
                        </div>
                    </div>
                </div>
            );
        }

        if (slug.includes("medicine")) {
            return (
                <div>
                    <label className="block text-sm font-semibold mb-2 text-gray-700">
                        Medicine List / Requirements
                    </label>
                    <textarea
                        name="requirements"
                        onChange={handleServiceChange}
                        required
                        className="w-full border border-gray-200 p-4 rounded-2xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 outline-none transition-all h-36 font-medium"
                        placeholder="List the medicines. A representative will contact you for prescriptions if needed."
                    />
                </div>
            );
        }

        return (
            <div>
                <label className="block text-sm font-semibold mb-2 text-gray-700">
                    Request Details
                </label>
                <textarea
                    name="details"
                    onChange={handleServiceChange}
                    required
                    className="w-full border border-gray-200 p-4 rounded-2xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 outline-none transition-all h-36 font-medium"
                    placeholder="Detailed description of what you need..."
                />
            </div>
        );
    };

    return (
        <form
            onSubmit={handleSubmit}
            className="max-w-2xl mx-auto space-y-10 bg-white p-6 md:p-10 rounded-[2rem] border border-gray-100 shadow-xl shadow-gray-200/50"
        >
            <div className="space-y-6">
                <h2 className="text-2xl font-black text-gray-900 border-b-2 border-gray-100 pb-4">
                    1. Service Details
                </h2>
                {renderFields()}
            </div>

            <div className="space-y-6 pt-4">
                <h2 className="text-2xl font-black text-gray-900 border-b-2 border-gray-100 pb-4">
                    2. Customer Info
                </h2>
                <div className="space-y-4">
                    <div>
                        <label className="block text-sm font-semibold mb-2 text-gray-700">
                            Full Name
                        </label>
                        <input
                            type="text"
                            name="name"
                            value={customer.name}
                            onChange={handleCustomerChange}
                            required
                            className="w-full border border-gray-200 p-4 rounded-2xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 outline-none transition-all font-medium"
                            placeholder="John Doe"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-semibold mb-2 text-gray-700">
                            Phone Number (WhatsApp)
                        </label>
                        <input
                            type="tel"
                            name="phone"
                            value={customer.phone}
                            onChange={handleCustomerChange}
                            required
                            className="w-full border border-gray-200 p-4 rounded-2xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 outline-none transition-all font-medium"
                            placeholder="+91 99999 99999"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-semibold mb-2 text-gray-700">
                            Current Address
                        </label>
                        <textarea
                            name="address"
                            value={customer.address}
                            onChange={handleCustomerChange}
                            required
                            className="w-full border border-gray-200 p-4 rounded-2xl focus:ring-4 focus:ring-purple-100 focus:border-purple-500 outline-none transition-all h-32 font-medium"
                            placeholder="House Number, Street, Landmark..."
                        />
                    </div>
                </div>
            </div>

            {error && (
                <div className="p-4 bg-red-50 text-red-600 rounded-2xl text-sm font-bold border border-red-100 text-center">
                    {error}
                </div>
            )}

            <button
                type="submit"
                disabled={loading}
                className="w-full py-5 bg-purple-600 text-white font-black text-lg rounded-2xl hover:bg-purple-700 transition-colors shadow-lg shadow-purple-600/30 flex items-center justify-center gap-3 active:scale-[0.98] transform disabled:opacity-70 disabled:active:scale-100"
            >
                {loading ? (
                    <>
                        <Loader2 className="w-6 h-6 animate-spin" /> Processing...
                    </>
                ) : (
                    <>
                        <MapPin className="w-6 h-6" /> Share GPS & Request Service
                    </>
                )}
            </button>
            <p className="text-xs text-center text-gray-400 font-medium">
                We require your GPS location to provide accurate service. Your browser will
                prompt for permission.
            </p>
        </form>
    );
}

"use client";

import { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import "leaflet/dist/leaflet.css";
import L from "leaflet";
import { Loader2, Package } from "lucide-react";

// Fix leaflet default markers
const iconUrl = "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png";
const iconRetinaUrl = "https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png";
const shadowUrl = "https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png";

const defaultIcon = L.icon({
    iconUrl,
    iconRetinaUrl,
    shadowUrl,
    iconSize: [25, 41],
    iconAnchor: [12, 41],
    popupAnchor: [1, -34],
    shadowSize: [41, 41]
});

// Custom icons based on status
const createStatusIcon = (color: string) => L.divIcon({
    className: "custom-div-icon",
    html: `<div style="background-color: ${color}; width: 24px; height: 24px; border-radius: 50%; border: 3px solid white; box-shadow: 0 4px 6px rgba(0,0,0,0.3);"></div>`,
    iconSize: [24, 24],
    iconAnchor: [12, 12]
});

const statusColors = {
    pending: "#f59e0b",
    processing: "#3b82f6",
    shipped: "#8b5cf6"
};

export default function LiveTrackingMap() {
    const [orders, setOrders] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    const fetchOrders = async () => {
        try {
            const res = await fetch("/api/admin/orders/active");
            const data = await res.json();
            if (data.success) {
                setOrders(data.data);
            }
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchOrders();
        // Refresh every 30 seconds
        const interval = setInterval(fetchOrders, 30000);
        return () => clearInterval(interval);
    }, []);

    if (loading) return <div className="h-[600px] flex items-center justify-center bg-gray-50 rounded-3xl border border-gray-200"><Loader2 className="w-8 h-8 animate-spin text-blue-600" /></div>;

    const center: [number, number] = orders.length > 0
        ? [orders[0].lat, orders[0].lng]
        : [17.3850, 78.4867]; // Default Hyderabad

    return (
        <div className="h-[600px] w-full rounded-3xl overflow-hidden shadow-sm border border-gray-200 relative">
            <MapContainer center={center} zoom={12} scrollWheelZoom={true} style={{ height: "100%", width: "100%" }}>
                <TileLayer
                    attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
                    url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
                />

                {orders.map((order) => {
                    const iconColor = statusColors[order.status as keyof typeof statusColors] || "#6b7280";
                    return (
                        <Marker
                            key={order.id}
                            position={[order.lat, order.lng]}
                            icon={createStatusIcon(iconColor)}
                        >
                            <Popup className="rounded-2xl shadow-xl border-0 p-0 m-0 custom-popup">
                                <div className="p-2 min-w-[220px]">
                                    <div className="flex items-center gap-2 mb-3 pb-3 border-b border-gray-100">
                                        <div className="bg-blue-50 p-2 rounded-full"><Package className="w-5 h-5 text-blue-600" /></div>
                                        <h3 className="font-bold text-gray-900 text-base">{order.customerName}</h3>
                                    </div>
                                    <div className="space-y-2 text-sm mb-4">
                                        <p className="flex justify-between items-center"><span className="text-gray-500 font-medium">Status:</span> <strong className="uppercase bg-gray-50 px-2 py-0.5 rounded-md text-xs" style={{ color: iconColor }}>{order.status}</strong></p>
                                        <p className="flex justify-between"><span className="text-gray-500 font-medium">Value:</span> <strong className="text-gray-900">₹{order.total}</strong></p>
                                        <p className="flex justify-between"><span className="text-gray-500 font-medium">Time:</span> <strong className="text-gray-900">{order.time}</strong></p>
                                    </div>
                                    <button className="w-full py-2 bg-gray-900 hover:bg-gray-800 transition-colors text-white text-xs font-bold rounded-xl" onClick={() => window.open(`/admin/orders`, '_blank')}>
                                        Manage Order
                                    </button>
                                </div>
                            </Popup>
                        </Marker>
                    )
                })}
            </MapContainer>

            {/* Legend Overlay */}
            <div className="absolute bottom-6 left-6 z-[400] bg-white p-4 rounded-2xl shadow-xl border border-gray-100">
                <h4 className="font-bold text-sm text-gray-900 mb-3 border-b border-gray-100 pb-2">Live Map Legend</h4>
                <div className="space-y-3 text-xs font-bold text-gray-700">
                    <div className="flex items-center gap-3"><div className="w-4 h-4 rounded-full bg-amber-500 border-2 border-white shadow-sm ring-1 ring-black/5"></div> Pending</div>
                    <div className="flex items-center gap-3"><div className="w-4 h-4 rounded-full bg-blue-500 border-2 border-white shadow-sm ring-1 ring-black/5"></div> Processing</div>
                    <div className="flex items-center gap-3"><div className="w-4 h-4 rounded-full bg-purple-500 border-2 border-white shadow-sm ring-1 ring-black/5"></div> Shipped (On the way)</div>
                </div>
                <div className="mt-4 pt-2 border-t border-gray-50 font-medium text-[10px] text-gray-400 text-right flex items-center justify-end gap-1">
                    <span className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></span> Auto-refreshes 30s
                </div>
            </div>

            <style>{`
                .leaflet-popup-content-wrapper { border-radius: 1rem; padding: 0; box-shadow: 0 10px 15px -3px rgb(0 0 0 / 0.1), 0 4px 6px -4px rgb(0 0 0 / 0.1); }
                .leaflet-popup-content { margin: 10px 12px; }
            `}</style>
        </div>
    );
}

"use client";

import { useEffect, useState, useRef } from "react";
import { toast } from "sonner";

export default function PendingOrderBadge() {
    const [count, setCount] = useState(0);
    const prevCountRef = useRef(0);

    useEffect(() => {
        const fetchCount = async () => {
            try {
                const res = await fetch("/api/admin/orders/pending-count");
                const data = await res.json();
                if (data.success) {
                    const newCount = data.count;

                    // If count increased, alert the admin
                    if (newCount > prevCountRef.current && prevCountRef.current !== 0) {
                        toast('🔔 New Order Received!', {
                            description: `You have ${newCount} pending orders.`,
                            action: {
                                label: 'View Orders',
                                onClick: () => window.location.href = '/admin/orders',
                            },
                            duration: 10000,
                        });

                        // Play a notification sound
                        try {
                            const audio = new Audio('/notification.mp3');
                            audio.play().catch(() => {});
                        } catch (e) {
                            // ignore audio error
                        }
                    }

                    setCount(newCount);
                    prevCountRef.current = newCount;
                }
            } catch (error) {
                console.error("Failed to fetch pending orders count");
            }
        };

        // Fetch immediately on mount
        fetchCount();

        // Poll every 10 seconds for faster updates
        const interval = setInterval(fetchCount, 10000);
        return () => clearInterval(interval);
    }, []);

    if (count === 0) return null;

    return (
        <span className="ml-auto inline-flex items-center justify-center px-2 py-0.5 text-xs font-bold text-white bg-red-500 rounded-full animate-pulse">
            {count}
        </span>
    );
}

