"use client";

import React, { createContext, useContext, useState, useEffect, ReactNode } from "react";

export interface CartItem {
    productId: string;
    name: string;
    price: number;
    quantity: number;
}

interface CartContextProps {
    cart: CartItem[];
    addToCart: (item: CartItem) => void;
    removeFromCart: (productId: string) => void;
    updateQuantity: (productId: string, quantity: number) => void;
    clearCart: () => void;
    cartTotal: number;
}

const CartContext = createContext<CartContextProps | undefined>(undefined);

export function CartProvider({ children }: { children: ReactNode }) {
    const [cart, setCart] = useState<CartItem[]>([]);

    useEffect(() => {
        const stored = localStorage.getItem("hypercart");
        if (stored) {
            try {
                setCart(JSON.parse(stored));
            } catch (e) {
                console.error("Failed to parse cart data from local storage", e);
            }
        }
    }, []);

    useEffect(() => {
        localStorage.setItem("hypercart", JSON.stringify(cart));
    }, [cart]);

    const addToCart = (item: CartItem) => {
        setCart((prev) => {
            const existing = prev.find((i) => i.productId === item.productId);
            if (existing) {
                return prev.map((i) =>
                    i.productId === item.productId
                        ? { ...i, quantity: i.quantity + item.quantity }
                        : i
                );
            }
            return [...prev, item];
        });
    };

    const removeFromCart = (productId: string) => {
        setCart((prev) => prev.filter((i) => i.productId !== productId));
    };

    const updateQuantity = (productId: string, quantity: number) => {
        if (quantity <= 0) {
            removeFromCart(productId);
            return;
        }
        setCart((prev) =>
            prev.map((i) => (i.productId === productId ? { ...i, quantity } : i))
        );
    };

    const clearCart = () => setCart([]);

    const cartTotal = cart.reduce((total, item) => total + item.price * item.quantity, 0);

    return (
        <CartContext.Provider
            value={{
                cart,
                addToCart,
                removeFromCart,
                updateQuantity,
                clearCart,
                cartTotal,
            }}
        >
            {children}
        </CartContext.Provider>
    );
}

export function useCart() {
    const context = useContext(CartContext);
    if (!context) {
        throw new Error("useCart must be used within a CartProvider");
    }
    return context;
}

import mongoose from "mongoose";

const MONGODB_URI = process.env.MONGODB_URI!;

if (!MONGODB_URI) {
  throw new Error(
    "Please define the MONGODB_URI environment variable inside .env.local"
  );
}

let cached = (global as any).mongoose;

if (!cached) {
  cached = (global as any).mongoose = { conn: null, promise: null };
}

async function connectToDatabase() {
  if (cached.conn) {
    return cached.conn;
  }

  if (!cached.promise) {
    const opts = {
      bufferCommands: false,
    };

    cached.promise = mongoose.connect(MONGODB_URI, opts).then((mongoose) => {
      return mongoose;
    });
  }
  cached.conn = await cached.promise;
  return cached.conn;
}

export default connectToDatabase;

import mongoose, { Schema, Document } from "mongoose";

export interface IOrder extends Document {
    type: "product" | "service";
    userId?: string;
    items?: Array<{
        productId: string;
        name: string;
        price: number;
        quantity: number;
    }>;
    serviceCategory?: string;
    serviceDetails?: any;
    status: "pending" | "processing" | "shipped" | "delivered" | "cancelled";
    subtotal: number;
    deliveryFee: number;
    platformFee: number;
    tax: number;
    promoCode?: string;
    walletUsed?: number;
    total: number;
    tipAmount?: number;
    paymentMethod?: "cod" | "upi" | "wallet" | "razorpay";
    transactionId?: string;
    customerName: string;
    customerPhone: string;
    address: string;
    latitude: number;
    longitude: number;
    riderId?: string;
    riderLocation?: {
        latitude: number;
        longitude: number;
    };
    deliveryStatus: "pending" | "assigned" | "accepted" | "declined" | "picked_up" | "out_for_delivery" | "delivered" | "cancelled";
    estimatedDeliveryTime?: Date;
    createdAt: Date;
    updatedAt: Date;
}

const OrderSchema: Schema = new Schema(
    {
        type: { type: String, enum: ["product", "service"], required: true },
        userId: { type: String },
        items: [
            {
                productId: { type: String },
                name: { type: String },
                price: { type: Number },
                quantity: { type: Number },
            },
        ],
        serviceCategory: { type: String },
        serviceDetails: { type: Schema.Types.Mixed },
        status: {
            type: String,
            enum: ["pending", "processing", "shipped", "delivered", "cancelled"],
            default: "pending"
        },
        subtotal: { type: Number, required: true },
        deliveryFee: { type: Number, required: true },
        platformFee: { type: Number, required: true },
        tax: { type: Number, required: true },
        discountAmount: { type: Number, default: 0 },
        promoCode: { type: String },
        walletUsed: { type: Number, default: 0 },
        total: { type: Number, required: true },
        tipAmount: { type: Number, default: 0 },
        paymentMethod: { type: String, enum: ["cod", "upi", "wallet", "razorpay"], default: "cod" },
        transactionId: { type: String },
        customerName: { type: String, required: true },
        customerPhone: { type: String, required: true },
        address: { type: String, required: true },
        latitude: { type: Number, required: true },
        longitude: { type: Number, required: true },
        riderId: { type: mongoose.Schema.Types.ObjectId, ref: "User" },
        riderLocation: {
            latitude: { type: Number },
            longitude: { type: Number }
        },
        deliveryStatus: {
            type: String,
            enum: ["pending", "assigned", "accepted", "declined", "picked_up", "out_for_delivery", "delivered", "cancelled"],
            default: "pending"
        },
        estimatedDeliveryTime: { type: Date }
    },
    { timestamps: true }
);

export default mongoose.models.Order || mongoose.model<IOrder>("Order", OrderSchema);
